$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_b878a67f82524d412dae79ad597ff402'] = 'Rader eldre enn denne verdien fjernes fra connections, connections_source og connections_page.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_5ee406d769ac3887713d3308a0d01601'] = 'Angi antall dager rå PrestaShop-besøksstatistikk skal beholdes. Eksempel: 60 betyr at modulen beholder de siste 60 dagene og sletter eldre poster fra ps_connections, ps_connections_source og ps_connections_page. Ikke sett dette til 1 med mindre du er sikker på at du ikke trenger nylig besøksstatistikk.';
