$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_631c4c75cb36e0fcee3da42ef67e730e'] = 'Maksimalt antall tilkoblinger behandlet i én batch.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_acbc6e359c79ace4ef9b5398148c13e2'] = 'Angi hvor mange hovedtilkoblingsposter som kan behandles i én intern batch. Mindre verdier er tryggere på svak hosting, men krever flere cron-kjøringer. Større verdier rydder raskere, men kan holde databaselåser lenger. Anbefalt startverdi: 1000 til 5000; øk kun etter test av kjøretid.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_2806977593fb4c23003cc11306b135d1'] = 'Maksimalt antall batcher per kjøring';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_d31a094a19379b58b63b51ef0f9d9362'] = 'Begrenser hvor mye arbeid én cron-kjøring kan gjøre.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_e221a5a91ea62a43adc5bb15614eb578'] = 'Angi hvor mange batcher som kan kjøres under én cron-kjøring. Totalt mulige slettede hovedposter per kjøring er omtrent Batchstørrelse multiplisert med Maksimalt antall batcher. Eksempel: 5000 og 10 betyr opptil rundt 50000 poster i én cron-kjøring. Senk verdien hvis butikken blir treg under rydding.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_a1a47524ffa9c839887703df1fbe70a3'] = 'Tøm ps_layered_filter_block';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_924684322fe68e56ef9205e7f480f598'] = 'Tømmer cache for fasettert/layered søkeblokk med TRUNCATE TABLE. Tabellen gjenopprettes tom av MySQL/MariaDB.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_92a6452eb793565a92aa28e5f9a3f2e5'] = 'Aktiver bare hvis ps_layered_filter_block vokser for mye eller inneholder utdatert cache for fasettert søk. Dette sletter ikke produkter, kategorier eller layered-prisindeksen. Etter rydding kan PrestaShop eller søkemodulen bygge cachen på nytt ved behov.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_bf45506cce2494894a9df6ff4bdf83ae'] = 'Aggreger trafikkildestatistikk før sletting';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_d7e1a0c7e7973ebcde37aa659525105d'] = 'Lagrer daglige oppsummerte trafikkildestatistikker før rå rader slettes.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ae729759e10d7a626a8622321932a1f4'] = 'Når aktivert lagrer modulen et lite daglig sammendrag før rå PrestaShop-statistikk fjernes. Den beholder tellinger som besøk, sidevisninger, kildedomene og UTM-verdier. IP-adresser, fullstendige referrer-URL-er eller user-agent-strenger lagres ikke. Deaktiver hvis du bare vil slette og ikke trenger historiske sammendrag.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ce2b282d224153cccd645f28504ab4e2'] = 'Oppbevaringsdager for aggregerte statistikker';
