$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ce2b282d224153cccd645f28504ab4e2'] = 'Oppbevaringsdager for aggregerte statistikker';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_c3b4d14f7bff29c221039e891918f2dd'] = 'Hvor lenge den lille daglige sammendragstabellen skal beholdes.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_a97a6a6ab09f48206a543fdc7321bb60'] = 'Angi hvor mange dager aggregerte trafikkildesammendrag skal ligge i modultabellen. Eksempel: 730 beholder omtrent to år med daglige sammendrag. Dette påvirker bare ps_jooim_dbcleaner_traffic_daily, ikke de opprinnelige PrestaShop-statistikktabellene.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_4d4c70d739ad72835a8b62a81e07c611'] = 'Tidsavbrudd for gammel lås i sekunder';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ef4f59605eb7e54ec7df26e3755b7edf'] = 'Beskyttelse mot at to ryddeprosesser kjører samtidig.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_2c1824ea38ec688698a26f01a46e6b16'] = 'Angi antall sekunder før en uferdig rydde-lås anses som forlatt. Dette beskytter databasen mot to samtidige cron-kjøringer. Anbefalt verdi: 7200. Senk bare hvis cron garantert avsluttes raskt.';
